const http = require\('http'\);
const TOKEN = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpZCI6MSwidXNlcm5hbWUiOiJCdXNieSIsImlhdCI6MTc3MzU4MTU5M30.o2nlQqc8caD13vyqumFlkUANmJWmsJV0GWv4gKBL0ZU';

async function test\(\) {
  const fetch = \(await import\('node-fetch'\)\).default;

  // Test achievements for Hogwarts Legacy \(id=1347, external_id=1693340366\)
  console.log\('=== Testing Achievements: Hogwarts Legacy ==='\);
  const achRes = await fetch\('http://localhost:3000/api/launcher/games/1347/details', {
    headers: { Authorization: 'Bearer ' + TOKEN }
  }\);
  const achData = await achRes.json\(\);
  const achs = JSON.parse\(achData.achievements || '[]'\);
  console.log\('Achievement count:', achs.length\);
  achs.slice\(0,3\).forEach\(a => console.log\(' -', a.name, '| unlocked:', a.unlocked, '| icon:', !!a.icon\)\);
  if \(!achs.length\) console.log\('No achievements returned - checking error:', JSON.stringify\(achData\).slice\(0,200\)\);

  // Test friends for Hogwarts Legacy  
  console.log\('\\n=== Testing Friends: Hogwarts Legacy ==='\);
  const frRes = await fetch\('http://localhost:3000/api/launcher/games/1347/friends', {
    headers: { Authorization: 'Bearer ' + TOKEN }
  }\);
  const friends = await frRes.json\(\);
  console.log\('Friends count:', friends.length\);
  friends.forEach\(f => console.log\(' -', f.username, '| status:', f.online_status, '| game:', f.current_game\)\);
  if \(!friends.length\) console.log\('No friends returned'\);
}
test\(\).catch\(e => { console.error\('Test error:', e.message\); process.exit\(1\); }\);
